patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..dce3ccaa737c 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4577,7 +4577,7 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,

   if (Cond->getType() == TrueVal->getType()) {
     // select i1 Cond, i1 true, i1 false --> i1 Cond
-    if (match(TrueVal, m_One()) && match(FalseVal, m_ZeroInt()))
+    if (match(TrueVal, m_One()) && match(FalseVal, m_Zero()))
       return Cond;

     // (X && Y) ? X : Y --> Y (commuted 2 ways)
@@ -4590,11 +4590,11 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,

     // (X || Y) ? false : X --> false (commuted 2 ways)
     if (match(Cond, m_c_LogicalOr(m_Specific(FalseVal), m_Value())) &&
-        match(TrueVal, m_ZeroInt()))
+        match(TrueVal, m_Zero()))
       return ConstantInt::getFalse(Cond->getType());

     Value *X, *Y;
-    if (match(FalseVal, m_ZeroInt())) {
+    if (match(FalseVal, m_Zero())) {
       // !(X || Y) && X --> false (commuted 2 ways)
       if (match(Cond, m_Not(m_c_LogicalOr(m_Specific(TrueVal), m_Value()))))
         return ConstantInt::getFalse(Cond->getType());
@@ -4607,6 +4607,15 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
     }
+    // select (select InnerCond, InnerTrue, false), true, FalseVal --> FalseVal if FalseVal == InnerTrue or FalseVal == InnerCond
+    // select (select InnerCond, false, InnerTrue), true, FalseVal --> FalseVal if FalseVal == InnerTrue or FalseVal == InnerCond
+    Value *InnerCond, *InnerTrue;
+    if (match(Cond, m_Select(m_Value(InnerCond), m_Value(InnerTrue), m_Zero())) &&
+        match(TrueVal, m_One()) && (FalseVal == InnerTrue || FalseVal == InnerCond))
+      return FalseVal;
+    if (match(Cond, m_Select(m_Value(InnerCond), m_Zero(), m_Value(InnerTrue))) &&
+        match(TrueVal, m_One()) && (FalseVal == InnerTrue || FalseVal == InnerCond))
+      return FalseVal;
   }

   // select ?, X, X -> X
@@ -4615,7 +4624,7 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,

   if (Cond == TrueVal) {
     // select i1 X, i1 X, i1 false --> X (logical-and)
-    if (match(FalseVal, m_ZeroInt()))
+    if (match(FalseVal, m_Zero()))
       return Cond;
     // select i1 X, i1 X, i1 true --> true
     if (match(FalseVal, m_One()))
@@ -4626,7 +4635,7 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
     if (match(TrueVal, m_One()))
       return Cond;
     // select i1 X, i1 false, i1 X --> false
-    if (match(TrueVal, m_ZeroInt()))
+    if (match(TrueVal, m_Zero()))
       return ConstantInt::getFalse(Cond->getType());
   }

